    if (elem_19 >= blk) return;

    int item_11 = blk - 1 - elem_19;

    // Use local arrays in registers/memory for the block
    int elem_23[(BLOCK_SIZE + 1) * (BLOCK_SIZE+1)];
    int item_16[BLOCK_SIZE * BLOCK_SIZE];

    // Load referrence
    for ( int i = 0; i < BLOCK_SIZE; ++i )
    {
