void nw_optimized(int *input_itemsets, int *tmp_0, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int total_blocks = (max_cols-1)/BLOCK_SIZE;

    int *d_input, *d_ref;
    size_t size = (size_t)max_rows * max_cols * sizeof(int);

    cudaMalloc(&d_input, size);
    cudaMalloc(&d_ref, size);

    cudaMemcpy(d_input, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ref, referrence, size, cudaMemcpyHostToDevice);

    printf("Processing top-left matrix\n");

    for( int blk = 1; blk <= total_blocks; blk++ )
    {
        int threads = blk;
        if (threads > BLOCK_SIZE) threads = BLOCK_SIZE; 

        nw_optimized_kernel_top<<<1, threads>>>(d_input, d_ref, max_rows, max_cols, penalty);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for ( int blk = 2; blk <= total_blocks; blk++ )
    {
        int count = total_blocks - (blk - 1);
        if (count <= 0) continue;

        nw_optimized_kernel_bottom<<<1, count>>>(d_input, d_ref, max_rows, max_cols, penalty, total_blocks);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(input_itemsets, d_input, size, cudaMemcpyDeviceToHost);

    cudaFree(d_input);
    cudaFree(d_ref);
}

